using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Greets a user by name.")]
    public static string Greet(
        [Description("The name of the user to greet")] string name) =>
        $"Hello, {name}! Welcome to the MCP server.";

    [McpServerTool, Description("Adds two numbers together and returns the result.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b) =>
        a + b;
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { EnableCaching = true, EnableLogging = true }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "config://app/status", Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns the current server status and uptime.")]
    public static string GetServerStatus() =>
        JsonSerializer.Serialize(new
        {
            Status = "Healthy",
            StartedAt = Program.StartTime,
            Uptime = DateTime.UtcNow - Program.StartTime
        }, new JsonSerializerOptions { WriteIndented = true });
}

